"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[56185],{54073:(e,n,i)=>{i.r(n),i.d(n,{data:()=>l});const l={key:"v-5d18972d",path:"/openlayers/guide/%E7%94%A8OpenLayers%203%E5%8A%A0%E8%BD%BDBing%E5%9C%A8%E7%BA%BF%E4%B8%AD%E6%96%87%E7%89%88%E5%9C%B0%E5%9B%BE.html",title:"用Openlayers3加载Bing在线中文版地图",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:2}]},filePathRelative:"openlayers/guide/用OpenLayers 3加载Bing在线中文版地图.md"}},69670:(e,n,i)=>{i.r(n),i.d(n,{default:()=>m});var l=i(57293);const s=(0,l._)("h1",{id:"用openlayers3加载bing在线中文版地图",tabindex:"-1"},[(0,l._)("a",{class:"header-anchor",href:"#用openlayers3加载bing在线中文版地图","aria-hidden":"true"},"#"),(0,l.Uk)(" 用Openlayers3加载Bing在线中文版地图")],-1),t=(0,l.Uk)("OpenLayers 3中提供了加载Bing地图的source "),d={href:"https://link.jianshu.com/?t=http://openlayers.org/en/v3.13.1/apidoc/ol.source.BingMaps.html",target:"_blank",rel:"noopener noreferrer"},r=(0,l._)("code",null,"ol.source.BingMaps",-1),a=(0,l.Uk)("，但是并不支持中文，构造函数的参数"),u=(0,l._)("code",null,"culture",-1),c=(0,l.Uk)("设置为中国是不行的，应该是Bing地图目前并没有提供中国区域的瓦片在线服务。但其实我们浏览Bing地图，看到的是中文版的地图。"),v=(0,l.uE)('<p>那么能否直接加载我们看到的中文版的Bing地图呢？OpenLayers针对瓦片地图提供了<code>ol.source.XYZ</code>和对应的<code>ol.layer.Tile</code>，可以帮助我们加载，之前的离线瓦片地图就是通过这种方式加载的 。 下面用同样的方式，我尝试加载Bing地图，遇到了稍许麻烦，主要在Tile的url拼接上。下面直接上代码：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>&lt;html&gt;\n\n&lt;head&gt;\n  &lt;title&gt;演示在ol3中加载Bing在线地图&lt;/title&gt;\n  &lt;link rel=&quot;stylesheet&quot; type=&quot;text/css&quot; href=&quot;ol3.7.0/ol.css&quot;&gt;\n  &lt;script type=&quot;text/javascript&quot; src=&quot;ol-debug.js&quot; charset=&quot;utf-8&quot;&gt;&lt;/script&gt;\n&lt;/head&gt;\n\n&lt;body&gt;\n    &lt;div id=&quot;map&quot; style=&quot;width:100%;&quot;&gt;&lt;/div&gt;\n    &lt;script&gt;\n        \n        // 创建地图\n        new ol.Map({\n            layers: [\n                new ol.layer.Tile({\n                    source: new ol.source.XYZ({\n                        wrapX: false,\n                        tileUrlFunction: tileUrlFunction\n                    })\n                })\n            ],\n            view: new ol.View({\n                center: [0, 0],\n                zoom: 2\n            }),\n            target: &quot;map&quot;\n        });\n        \n        // Bing在线地图的url构造函数\n        function tileUrlFunction(coord, params1, params2) {\n            return getVETileUrl(coord[0], coord[1], -coord[2] - 1);\n        }\n        \n        function getVETileUrl(z, x, y) {\n            for(var a=&quot;&quot;,c=x,d=y,e=0;e&lt;z;e++) {\n                a=((c&amp;1)+2*(d&amp;1)).toString()+a;\n                c&gt;&gt;=1;\n                d&gt;&gt;=1\n            }\n            return &#39;http://dynamic.t0.tiles.ditu.live.com/comp/ch/&#39; + a + &#39;?it=G,VE,BX,L,LA&amp;mkt=zh-cn,syr&amp;n=z&amp;og=111&amp;ur=CN&#39;\n        }\n    &lt;/script&gt;\n&lt;/body&gt;\n\n&lt;/html&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面是完整代码，复制到本地保存成页面，然后根据OpenLayers 3的库的位置，修改一下代码中的库位置，即可打开浏览看到中文版的Bing地图了。</p>',3),o={},m=(0,i(63243).Z)(o,[["render",function(e,n){const i=(0,l.up)("ExternalLinkIcon");return(0,l.wg)(),(0,l.iD)(l.HY,null,[s,(0,l._)("p",null,[t,(0,l._)("a",d,[r,(0,l.Wm)(i)]),a,u,c]),v],64)}]])},63243:(e,n)=>{n.Z=(e,n)=>{const i=e.__vccOpts||e;for(const[e,l]of n)i[e]=l;return i}}}]);